import clsx from 'clsx';
import { forwardRef, type HTMLAttributes } from 'react';

import { defaultChartSize } from '../../../../../core/styles/defaultChartValues.sty.js';
import { useDataDtrumContext } from '../../../context/DataDtrumContext.js';

type MagnifierProps = HTMLAttributes<HTMLDivElement>;

export const Magnifier = forwardRef<HTMLDivElement, MagnifierProps>(
  (props: MagnifierProps, forwardedRef) => {
    const { dataDtrumMask, dataDtrumAllow } = useDataDtrumContext();
    return (
      <div
        {...props}
        ref={forwardedRef}
        className={clsx(props.className, defaultChartSize)}
        data-dtrum-mask={dataDtrumMask}
        data-dtrum-allow={dataDtrumAllow}
      >
        {props.children}
      </div>
    );
  },
);
